#ifndef DSTRUCT_H
#define DSTRUCT_H

#include <stddef.h>
#include <stdbool.h>

/* Dynamic array (vector) for int values */
typedef struct {
    int *data;
    size_t len;
    size_t capacity;
} Vec;

Vec *vec_create(void);
void vec_destroy(Vec *v);
bool vec_push(Vec *v, int value);
bool vec_pop(Vec *v, int *out);
int  vec_get(const Vec *v, size_t index);
size_t vec_len(const Vec *v);

#endif

#include "dstruct.h"
#include <stdlib.h>
#include <assert.h>

#define INITIAL_CAPACITY 4

Vec *vec_create(void) {
    Vec *v = malloc(sizeof(Vec));
    if (!v) return NULL;
    v->data = malloc(sizeof(int) * INITIAL_CAPACITY);
    if (!v->data) {
        free(v);
        return NULL;
    }
    v->len = 0;
    v->capacity = INITIAL_CAPACITY;
    return v;
}

void vec_destroy(Vec *v) {
    if (v) {
        free(v->data);
        free(v);
    }
}

bool vec_push(Vec *v, int value) {
    if (v->len >= v->capacity) {
        size_t new_cap = v->capacity * 2;
        int *new_data = realloc(v->data, sizeof(int) * new_cap);
        if (!new_data) return false;
        v->data = new_data;
        v->capacity = new_cap;
    }
    v->data[v->len++] = value;
    return true;
}

bool vec_pop(Vec *v, int *out) {
    if (v->len == 0) return false;
    v->len--;
    if (out) *out = v->data[v->len];
    return true;
}

int vec_get(const Vec *v, size_t index) {
    assert(index < v->len);
    return v->data[index];
}

size_t vec_len(const Vec *v) {
    return v->len;
}

#include <stdio.h>
#include <assert.h>
#include "dstruct.h"

void test_push_and_get(void) {
    Vec *v = vec_create();
    vec_push(v, 10);
    vec_push(v, 20);
    vec_push(v, 30);
    assert(vec_len(v) == 3);
    assert(vec_get(v, 0) == 10);
    assert(vec_get(v, 1) == 20);
    assert(vec_get(v, 2) == 30);
    vec_destroy(v);
    printf("PASS: test_push_and_get\n");
}

void test_auto_resize(void) {
    Vec *v = vec_create();
    for (int i = 0; i < 100; i++) {
        vec_push(v, i * 2);
    }
    assert(vec_len(v) == 100);
    assert(vec_get(v, 99) == 198);
    assert(vec_get(v, 0) == 0);
    vec_destroy(v);
    printf("PASS: test_auto_resize\n");
}

void test_pop(void) {
    Vec *v = vec_create();
    vec_push(v, 5);
    vec_push(v, 10);
    int val;
    bool ok = vec_pop(v, &val);
    assert(ok && val == 10);
    assert(vec_len(v) == 1);
    ok = vec_pop(v, &val);
    assert(ok && val == 5);
    assert(vec_len(v) == 0);
    ok = vec_pop(v, &val);
    assert(!ok);
    vec_destroy(v);
    printf("PASS: test_pop\n");
}

int main(void) {
    test_push_and_get();
    test_auto_resize();
    test_pop();
    printf("All tests passed!\n");
    return 0;
}
